const brief = $json.discovery_brief || {};
const dossier = $json.research_dossier || {};
const client = $json.client_name || 'Client';
const problem = brief.problem_summary || 'Key growth bottlenecks identified during discovery.';
const goals = brief.goal_summary || 'Define and execute a profitable growth system.';

const sectionTitles = [
  'Executive Summary',
  'Scope of Services',
  'Strategy and Approach',
  'Budget and Pricing',
  'Terms and Conditions'
];

const sections = sectionTitles.map((title) => ({
  title,
  content: `TODO: Write ${title} for ${client} using transcript insights, goals, and research findings.`
}));

const body = [
  `Marketing Proposal for ${client}`,
  '',
  ...sections.flatMap((s) => [`## ${s.title}`, s.content, ''])
].join('\n');

return [{
  json: {
    ...$json,
    status: 'DRAFT_READY',
    proposal_section_draft: {
      case_id: $json.case_id,
      sections,
      draft_body_markdown: body
    },
    gmail_draft_payload: {
      case_id: $json.case_id,
      subject: `Marketing Proposal for ${client}`,
      body
    }
  }
}];

